code_after:
@Override // since 2.13
    public Object getAbsentValue(DeserializationContext ctxt) {
        // [databind#5861] Optionally map absent to MissingNode
        if (ctxt.isEnabled(JsonNodeFeature.MAP_ABSENT_TO_MISSING)) {
            return ctxt.getNodeFactory().missingNode();
        }
        return null;
    }
